+
+impl ModalManager {
+    /// Create a new modal manager with no active modal.
+    #[must_use]
+    pub const fn new() -> Self {
+        Self { active: None }
+    }
+
+    /// Returns `true` if a modal is currently active.
+    #[must_use]
+    pub fn is_active(&self) -> bool {
